#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long hour; if(scanf("%lld", &hour)!=1) break;
        long long minutes = hour * 60LL;
        long long seconds = hour * 3600LL;
        printf("%lld\n%lld\n", minutes, seconds);
    }
    return 0;
}

